import mongoose from "mongoose";

// Schema for Universal tinter catalog (colorants available on the dispensing machine).
const colorantSchema = new mongoose.Schema({
  code: { type: String, required: true, unique: true },
  name: { type: String, required: true },
  pigment: { type: String, required: true },
  maxMlPerLiter: { type: Number, required: true },
  sortOrder: { type: Number, required: true, default: 0 },
});

// Schema for Base paint catalog.
const baseSchema = new mongoose.Schema({
  code: { type: String, required: true, unique: true },
  name: { type: String, required: true },
  description: { type: String, required: true },
  maxLoadPct: { type: Number, required: true },
});

// Schema for individual colorant additions for a formula.
const formulaItemSchema = new mongoose.Schema({
  colorantCode: { type: String, required: true },
  mlPerLiter: { type: Number, required: true },
});

// Schema for Saved mixing formulas.
const formulaSchema = new mongoose.Schema({
  name: { type: String, required: true, index: true },
  baseCode: { type: String, required: true },
  notes: { type: String },
  isPreset: { type: Boolean, required: true, default: false },
  createdAt: { type: Date, default: Date.now },
  items: [formulaItemSchema], // Embedded items
});

// Mongoose Models
export const Colorant = mongoose.models.Colorant || mongoose.model("Colorant", colorantSchema);
export const Base = mongoose.models.Base || mongoose.model("Base", baseSchema);
export const Formula = mongoose.models.Formula || mongoose.model("Formula", formulaSchema);
